from pywinauto import Application


# йАТељТйБНеОЖеєґжЙУеН∞жОІдїґж†СзЪДеЗљжХ∞
def print_control_tree(control, depth=0):
    # ж†єжНЃжЈ±еЇ¶жЈїеК†зЉ©ињЫпЉМиЃ©е±ВзЇІеЕ≥з≥їдЄАзЫЃдЇЖзДґ
    indent = "вФВ   " * depth
    prefix = "вФЬвФАвФА " if depth > 0 else ""

    # жПРеПЦж†ЄењГдњ°жБѓ
    element_info = control.element_info
    text = control.window_text()
    control_type = element_info.control_type
    class_name = element_info.class_name

    # ж†ЉеЉПеМЦиЊУеЗЇпЉЪ[зЉ©ињЫ][еЙНзЉА] з±їеЮЛ | з±їеРН | жЦЗе≠Ч
    print(f'{indent}{prefix}[{control_type}] ({class_name}) - "{text}"')

    # иОЈеПЦељУеЙНжОІдїґзЪДзЫіжО•е≠РжОІдїґпЉМеєґйАТељТи∞ГзФ®иЗ™иЇЂ
    try:
        children = control.children()
        for child in children:
            print_control_tree(child, depth + 1)
    except Exception as _:
        # жЬЙдЇЫзЙєжЃКжОІдїґеПѓиГљжЧ†ж≥ХиОЈеПЦе≠РжОІдїґпЉМеК†дЄ™еЉВеЄЄжНХиОЈйШ≤ж≠Ґз®ЛеЇПеі©жЇГ
        pass


# ињЮжО•еєґиОЈеПЦй°ґе±Вз™ЧеП£
app = Application(backend="uia").connect(
    title_re=".*зљСдЄКдЇ§жШУз≥їзїЯ.*", timeout=10, control_type="Window"
)
topw = app.top_window()

print("=== еЉАеІЛйАТељТйБНеОЖжОІдїґж†С ===")
print_control_tree(topw)



